  "systemPrompts": [
    {
      "id": "001",
      "name": "用户帮助提示",
      "content": "请稍等，我将为您提供所需的信息。",
      "enabled": true,
      "version": "3.2"
    },
    {
      "id": "002",
      "name": "欢迎消息",
      "content": "欢迎您使用本系统！有任何问题，请随时提问。",
