    },
    {
      "key": "APIRateLimit",
      "value": "100 requests/day",
      "description": "每日API调用次数限制为100次。"
    },
  ],
  "internalTools": [
    {
      "name": "快速响应工具",
      "type": "text",
      "schema": {
        "fields": [
          { "name": "request", "type": "string" },
          { "name": "responseTime", "type": "integer" }
        ]
      }
    },
    {
      "name": "错误日志记录工具",
      "type": "log",
      "schema": {
        "fields": [
          { "name": "timestamp", "type": "datetime" },
          { "name": "level", "type": "string" },
          { "name": "message", "type": "string" }
        ]
      }
    }
  ]
}
```

